const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
return [{ json: { data: data, topic: r.topic, date: r.date, client: r.client, markdown: raw } }];

/* Jarvis brand kit v2 — env-driven theme (BRAND_PRIMARY/ACCENT/GOLD) + masthead + takeaways + sign-off */
var __jfs=null; try{__jfs=require('fs');}catch(e){}
function jbHex(v,d){ v=String(v||'').trim(); return /^#[0-9a-fA-F]{6}$/.test(v)?v:d; }
var JB_PRI=jbHex($env.BRAND_PRIMARY,'#0A1A2F'), JB_ACC=jbHex($env.BRAND_ACCENT,'#0E7C86'), JB_GOLD=jbHex($env.BRAND_GOLD,'#E7C76A');
function jbAvatarUri(){ if(!__jfs) return ''; var t=[['/config/branding/jarvis-avatar.png','image/png'],['/config/branding/jarvis-avatar.jpg','image/jpeg'],['/config/branding/jarvis-avatar.jpeg','image/jpeg'],['/config/branding/jarvis-avatar.svg','image/svg+xml']]; for(var i=0;i<t.length;i++){ try{ return 'data:'+t[i][1]+';base64,'+__jfs.readFileSync(t[i][0]).toString('base64'); }catch(e){} } return ''; }
var JB_SVG='<svg class="jav" viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="jbg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#0E7C86"/><stop offset="1" stop-color="#0A1A2F"/></linearGradient></defs><circle cx="32" cy="32" r="32" fill="url(#jbg)"/><rect x="19" y="21" width="26" height="22" rx="7" fill="#fff"/><circle cx="27" cy="32" r="3.2" fill="#0E7C86"/><circle cx="37" cy="32" r="3.2" fill="#0E7C86"/><rect x="27" y="38" width="10" height="2.4" rx="1.2" fill="#0E7C86"/><rect x="30.7" y="14" width="2.6" height="6" rx="1.3" fill="#9fe4d8"/><circle cx="32" cy="13" r="2.4" fill="#E7C76A"/><path d="M23 47h18l-3 4.5H26z" fill="#9fe4d8"/></svg>';
function jbEsc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
var JB_AV=jbAvatarUri(), JB_AVATAR=JB_AV?('<img src="'+JB_AV+'"/>'):JB_SVG;
// CSS injected into every render's <style>: :root theme vars + masthead + takeaways + sign-off.
var JB_CSS=":root{--jb-pri:"+JB_PRI+";--jb-acc:"+JB_ACC+";--jb-gold:"+JB_GOLD+"}"
+".jbmast{background:linear-gradient(120deg,var(--jb-pri),var(--jb-acc));color:#fff;border-radius:12px;padding:15px 20px;display:flex;align-items:center;justify-content:space-between;gap:14px;margin:0 0 16px}"
+".jbmast .jbk{font-size:10px;letter-spacing:3px;text-transform:uppercase;color:var(--jb-gold);font-weight:800}"
+".jbmast h1{font-family:Georgia,serif;font-size:25px;margin:4px 0 0;font-weight:800;line-height:1.12;color:#fff}"
+".jbmast .jbs{font-size:12px;color:#dbe9ee;margin-top:5px}"
+".jbmast .jbav img,.jbmast .jbav .jav{width:46px;height:46px;border-radius:50%;border:2px solid #9fe4d8;flex:0 0 auto;background:var(--jb-pri)}"
+".jkit-take{background:#F4F6F9;border:1px solid #E2E6EC;border-left:4px solid var(--jb-acc);border-radius:10px;padding:14px 18px;margin:22px 0 0;page-break-inside:avoid}.jkit-take .th{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--jb-pri);font-weight:800;margin:0 0 7px}.jkit-take ul{margin:0;padding-left:18px}.jkit-take li{font-size:13.5px;line-height:1.5;color:#2b3340;margin:5px 0}"
+".jkit-sign{display:flex;align-items:center;gap:12px;margin:20px 0 0;padding-top:14px;border-top:2px solid var(--jb-acc);page-break-inside:avoid}.jkit-sign img,.jkit-sign .jav{width:46px;height:46px;border-radius:50%;border:2px solid var(--jb-acc);flex:0 0 auto}.jkit-sign .nm{font-family:Georgia,serif;font-size:15px;color:var(--jb-pri);font-weight:700}.jkit-sign .rl{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:10px;letter-spacing:2px;text-transform:uppercase;color:var(--jb-acc);font-weight:800;margin-top:2px}";
function jbMast(kicker,title,sub){ return '<div class="jbmast"><div><div class="jbk">'+jbEsc(kicker)+'</div><h1>'+title+'</h1>'+(sub?'<div class="jbs">'+sub+'</div>':'')+'</div><span class="jbav">'+JB_AVATAR+'</span></div>'; }
function jTakeBox(takeaways){ var t=(takeaways||[]).filter(Boolean).slice(0,4); if(!t.length) return ''; return '<div class="jkit-take"><div class="th">Key takeaways &middot; Lessons learned</div><ul>'+t.map(function(x){return '<li>'+jbEsc(x)+'</li>';}).join('')+'</ul></div>'; }
function jSignoff(){ return '<div class="jkit-sign">'+JB_AVATAR+'<div><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Assistant</div></div></div>'; }
function jKitBlock(takeaways){ return jTakeBox(takeaways)+jSignoff(); }
/* back-compat aliases for renders that referenced the v1 prelude */
var JKIT_CSS=JB_CSS, JKIT_SVG=JB_SVG; function jKitEsc(s){ return jbEsc(s); }

const d=$json.data||{}; const topic=$json.topic||'Security'; const date=$json.date||''; const client=($json.client||'').toString();
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const byline = client? ('Prepared for '+client) : 'Security Awareness';
const Q=(d.questions||[]); const sp=d.spotThePhish||{}; const em=sp.email||{};
const letters=['A','B','C','D'];
function optList(q,showAns){ return '<ol class="opts">'+(q.options||[]).map(function(o,i){ var hit=(showAns && q.answer===i); return '<li'+(hit?' class="hit"':'')+'>'+esc(o)+(hit?' &#10003;':'')+'</li>'; }).join('')+'</ol>'; }
var emailCard='<div class="email"><div class="eh"><b>From:</b> '+esc(em.from||'')+'<br><b>Subject:</b> '+esc(em.subject||'')+'</div><div class="eb">'+((em.lines||[]).map(function(l){return '<p>'+esc(l)+'</p>';}).join(''))+'</div></div>';
var partQ=Q.map(function(q,i){ return '<div class="q"><div class="qn">'+(i+1)+'. '+esc(q.q)+'</div>'+optList(q,false)+'</div>'; }).join('');
var factQ=Q.map(function(q,i){ return '<div class="q"><div class="qn">'+(i+1)+'. '+esc(q.q)+'</div><div class="ans">Answer: '+(letters[q.answer]||'?')+' &mdash; '+esc((q.options||[])[q.answer]||'')+'</div><div class="why">'+esc(q.why||'')+'</div></div>'; }).join('');
var EXTRA=".opts{list-style:upper-alpha;margin:6px 0 0;padding-left:24px} .opts li{font-size:13.5px;line-height:1.5;margin:3px 0} .opts li.hit{color:#1E6B3A;font-weight:700} .q{margin:0 0 14px;page-break-inside:avoid} .qn{font-weight:700;font-size:14px;color:var(--jb-pri)} .ans{font-size:13px;color:#1E6B3A;font-weight:700;margin-top:4px} .why{font-size:12.5px;color:#5A6472} .email{border:1px solid #E2E6EC;border-radius:8px;overflow:hidden;margin:8px 0} .email .eh{background:#F3F6F8;padding:10px 14px;font-size:13px;color:#2b3340} .email .eb{padding:10px 14px} .email .eb p{margin:0 0 6px;font-size:13.5px} .rf{margin:8px 0;padding-left:20px} .rf li{font-size:13px;color:#8a1f1f;margin:4px 0}";
var CSS="@page{size:A4;margin:16mm 15mm 18mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,\"Segoe UI\",Arial,sans-serif;color:#11151c} .pg{page-break-after:always} .pg:last-child{page-break-after:auto} .kick{color:var(--jb-acc);letter-spacing:2px;font-weight:800;font-size:12px;text-transform:uppercase} h1.t{font-family:Georgia,serif;font-size:30px;color:var(--jb-pri);margin:6px 0 4px} .sub{color:#5A6472;font-size:13px;margin:0 0 18px} h2{font-family:Georgia,serif;font-size:19px;color:var(--jb-pri);margin:20px 0 10px;border-bottom:2px solid var(--jb-acc);padding-bottom:6px} p{font-size:14px;line-height:1.6;color:#2b3340} .foot{position:fixed;bottom:8mm;left:15mm;right:15mm;color:#9aa6b2;font-size:11px;border-top:1px solid #E2E6EC;padding-top:8px;display:flex;justify-content:space-between} .card{border:1px solid #E2E6EC;border-radius:8px;padding:14px 16px;margin:12px 0;page-break-inside:avoid} .card h3{margin:0 0 8px;font-family:Georgia,serif;font-size:16px;color:var(--jb-pri)} .pill{display:inline-block;background:#E6F4F1;color:var(--jb-acc);font-weight:800;font-size:11px;padding:3px 10px;border-radius:12px;letter-spacing:.5px}"+EXTRA+JKIT_CSS;
var participant='<div class="pg">'+jbMast('Awareness Quiz · Participant', esc(topic)+' — Quick Quiz', esc(d.intro||'Test your knowledge.'))+''+partQ+'<h2>Spot the Phish</h2><p>'+esc(sp.scenario||'Review the email below. How many warning signs can you spot?')+'</p>'+emailCard+'<div class="foot"><span>'+esc(byline)+'</span><span>'+esc(date)+'</span></div></div>';
var facilitator='<div class="pg">'+jbMast('Awareness Quiz · Facilitator key', 'Answer Key', esc(topic))+''+factQ+'<h2>Spot the Phish — Debrief</h2><p><b>Red flags:</b></p><ul class="rf">'+((sp.redFlags||[]).map(function(r){return '<li>'+esc(r)+'</li>';}).join(''))+'</ul><p><b>Verdict:</b> '+esc(sp.verdict||'')+'</p>'+jKitBlock(d.takeaways)+'<div class="foot"><span>'+esc(byline)+' · AI-generated — review before use</span><span>'+esc(date)+'</span></div></div>';
const html='<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'+participant+facilitator+'</body></html>';
const fileSafe=topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40)||'quiz';
return [{ json:{ html:html, topic:topic, date:date, fileSafe:fileSafe, outDir:'quiz', filePrefix:'quiz' } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'misc');
const name = (meta.filePrefix || 'asset') + '-' + (meta.fileSafe || 'item') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];
